package clusterspec

import (
	"strings"
	"testing"
)

// allEnabled mimics the default recipe set (everything on except DefaultDisabled).
func allEnabled() map[string]RecipeToggle {
	m := map[string]RecipeToggle{}
	for _, r := range Recipes {
		m[r.Name] = RecipeToggle{Enabled: !r.DefaultDisabled}
	}
	return m
}

func TestRenderManifestKustomization_Default(t *testing.T) {
	out := RenderManifestKustomization(allEnabled())
	mustContainAll(t, out, []string{
		"# GENERATED by",
		"kind: Kustomization",
		"resources:",
		"  - argocd",
		"  - external-secrets/cluster-secret-store-openbao.yaml",
		"  - linode-volume-labeler",
		"  - harbor/harbor-registry-s3-externalsecret.yaml",
		"  - observability/prometheus-rules/openbao-alerts.yaml",
		// volumeLabeler patch
		"patches:",
		"  - path: linode-volume-labeler-region-patch.yaml",
		"      kind: CronJob",
	})
}

func TestRenderManifestKustomization_DisableDropsResourcesAndPatch(t *testing.T) {
	recipes := allEnabled()
	recipes["harbor"] = RecipeToggle{Enabled: false}
	recipes["volumeLabeler"] = RecipeToggle{Enabled: false}
	out := RenderManifestKustomization(recipes)

	if strings.Contains(out, "harbor/") {
		t.Errorf("disabled harbor still present:\n%s", out)
	}
	if strings.Contains(out, "linode-volume-labeler") {
		t.Errorf("disabled volumeLabeler still present:\n%s", out)
	}
	// volumeLabeler was the only patch contributor → no patches block at all.
	if strings.Contains(out, "patches:") {
		t.Errorf("patches block should be gone when volumeLabeler is off:\n%s", out)
	}
}

func TestRenderArgoKustomization_WaveOrder(t *testing.T) {
	out := RenderArgoKustomization(allEnabled())
	// The wave order must be: project, cluster-foundation, …, openbao last.
	order := []string{
		"platform-support-project.yaml",
		"applications/cluster-foundation.yaml",
		"applications/external-secrets-operator.yaml",
		"applications/openbao.yaml",
	}
	last := -1
	for _, want := range order {
		i := strings.Index(out, want)
		if i < 0 {
			t.Fatalf("argocd kustomization missing %q:\n%s", want, out)
		}
		if i < last {
			t.Errorf("argocd resource %q out of wave order:\n%s", want, out)
		}
		last = i
	}
}

func mustContainAll(t *testing.T, s string, subs []string) {
	t.Helper()
	for _, sub := range subs {
		if !strings.Contains(s, sub) {
			t.Errorf("output missing %q:\n%s", sub, s)
		}
	}
}
